const isWebhook = $json.headers !== undefined || $json.body !== undefined;
let tags = [];
let buildId = null;
let source = 'schedule';
if (isWebhook) {
  source = 'webhook';
  const body = $json.body || {};
  tags = Array.isArray(body.tags) ? body.tags : [];
  buildId = body.build_id || null;
}
return { json: { source, tags, build_id: buildId } };

const rand = Math.random().toString(36).slice(2, 6);
const runId = `run_${new Date().toISOString()}_${rand}`;
// Reset per-run accumulators in workflow static data so re-runs start clean.
const staticData = $getWorkflowStaticData('global');
staticData['results_' + runId] = [];
staticData['skipped_' + runId] = [];
return { json: { ...$json, run_id: runId, started_at: new Date().toISOString() } };

const run = $('Initialize Run').first().json;
const tagFilter = run.tags || [];
const requiredByType = {
  api: ['endpoint', 'method'],
  db: ['db_query'],
  ui: ['ui_runner_webhook', 'ui_script_id']
};

function parseMaybeJson(val) {
  if (val == null || val === '') return undefined;
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch (e) { return val; }
}

const valid = [];
const skipped = [];

for (const item of $input.all()) {
  const row = item.json;
  if (String(row.active).toLowerCase() !== 'true') continue;
  if (tagFilter.length) {
    const rowTags = String(row.tags || '').split(',').map(t => t.trim()).filter(Boolean);
    if (!rowTags.some(t => tagFilter.includes(t))) continue;
  }
  const req = requiredByType[row.test_type] || [];
  const missing = req.filter(f => row[f] === undefined || row[f] === null || row[f] === '');
  if (missing.length) {
    skipped.push({ test_id: row.test_id, test_type: row.test_type, reason: `missing fields: ${missing.join(', ')}` });
    continue;
  }
  valid.push({
    ...row,
    // Coerce JSON-in-cells into real objects/arrays for downstream nodes.
    headers: parseMaybeJson(row.headers) || {},
    body: parseMaybeJson(row.body),
    expected_key_values: parseMaybeJson(row.expected_key_values) || {},
    expected_schema: parseMaybeJson(row.expected_schema),
    dynamic_fields: (function () {
      const df = parseMaybeJson(row.dynamic_fields);
      if (Array.isArray(df)) return df;
      if (typeof df === 'string') return df.split(',').map(s => s.trim()).filter(Boolean);
      return [];
    })(),
    expected_status: row.expected_status !== undefined && row.expected_status !== '' ? Number(row.expected_status) : null,
    known_flaky: String(row.known_flaky).toLowerCase() === 'true',
    run_id: run.run_id,
    source: run.source
  });
}

const staticData = $getWorkflowStaticData('global');
staticData['skipped_' + run.run_id] = skipped;

return valid.map(v => ({ json: v }));

// Carry the original test config forward from the loop input (Batch Controller),
// then attach the normalized 'actual' result. This keeps expected_* fields intact
// even though the execution nodes only return the raw response.
const cfg = $('Batch Controller').item.json;
const raw = $json;
let actual = {};
if (cfg.test_type === 'api') {
  const headers = raw.headers || {};
  actual = {
    status: raw.statusCode != null ? raw.statusCode : raw.status,
    body: raw.body != null ? raw.body : (raw.data != null ? raw.data : {}),
    latency_ms: headers['x-response-time'] != null ? Number(headers['x-response-time']) : null
  };
} else if (cfg.test_type === 'db') {
  actual = { status: null, body: Array.isArray(raw) ? raw : raw, latency_ms: null };
} else if (cfg.test_type === 'ui') {
  const b = raw.body != null ? raw.body : raw;
  actual = { status: b.status != null ? b.status : (raw.statusCode != null ? raw.statusCode : null), body: b, latency_ms: null };
} else {
  actual = { status: null, body: null, latency_ms: null, unsupported: true };
}
return { json: { ...cfg, actual } };

const t = $json;
const mismatches = [];
const dynamic = new Set(t.dynamic_fields || []);

function get(obj, path) {
  return String(path).split('.').reduce((o, k) => (o == null ? undefined : o[k]), obj);
}

if (t.actual && t.actual.unsupported) {
  return { json: { ...t, deterministic_verdict: 'UNSUPPORTED', mismatches: [{ field: 'test_type', expected: 'api|db|ui', actual: t.test_type }] } };
}

if (t.expected_status != null && t.actual.status !== t.expected_status) {
  mismatches.push({ field: 'status', expected: t.expected_status, actual: t.actual.status });
}

const kv = t.expected_key_values || {};
for (const [key, val] of Object.entries(kv)) {
  if (key.endsWith('_semantic') || key.endsWith('_min')) continue;
  const path = key;
  if (dynamic.has(path)) continue;
  const actualVal = get(t.actual.body, path);
  if (JSON.stringify(actualVal) !== JSON.stringify(val)) {
    mismatches.push({ field: path, expected: val, actual: actualVal });
  }
}

// Lightweight required-field check against expected_schema (no external deps).
if (t.expected_schema && t.expected_schema.required && Array.isArray(t.expected_schema.required)) {
  for (const field of t.expected_schema.required) {
    if (get(t.actual.body, field) === undefined) {
      mismatches.push({ field, expected: 'present (schema-required)', actual: undefined });
    }
  }
}

const hasSemanticAssertion = Object.keys(kv).some(k => k.endsWith('_semantic'));
const deterministic_verdict = (mismatches.length === 0 && !hasSemanticAssertion) ? 'PASS' : 'AMBIGUOUS';

return { json: { ...t, deterministic_verdict, mismatches } };

parameters.jsonBody:
={{ {
  model: 'claude-3-5-sonnet-20241022',
  max_tokens: 1024,
  temperature: 0,
  system: 'You are a senior QA engineer adjudicating one regression test result. Fields listed in dynamic_fields are EXPECTED to vary run-to-run and must never by themselves cause a FAIL. Do not treat cosmetic or reworded text as a failure unless the meaning changed. Respond with STRICT JSON ONLY, no prose, no markdown fences, matching exactly this shape: {\"verdict\":\"PASS|FAIL|FLAKY|NEEDS_REVIEW\",\"confidence\":0.0,\"root_cause_category\":\"REGRESSION|FLAKY|TEST_DATA_ISSUE|ENV_ISSUE|STALE_EXPECTATION|null\",\"reasoning\":\"...\",\"suggested_expected_value\":null}',
  messages: [{
    role: 'user',
    content: JSON.stringify({
      test_id: $json.test_id,
      test_name: $json.test_name,
      priority: $json.priority,
      known_flaky: $json.known_flaky,
      dynamic_fields: $json.dynamic_fields,
      expected_status: $json.expected_status,
      expected_key_values: $json.expected_key_values,
      actual: $json.actual,
      deterministic_mismatches: $json.mismatches
    })
  }]
} }}

