let verdict;
try {
  const resp = $json;
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '{}';
  const clean = text.replace(/```json/g, '').replace(/```/g, '').trim();
  verdict = JSON.parse(clean);
  if (!verdict || typeof verdict.verdict !== 'string') throw new Error('missing verdict');
} catch (e) {
  verdict = { verdict: 'NEEDS_REVIEW', confidence: 0, root_cause_category: 'ENV_ISSUE', reasoning: 'AI response could not be parsed; flagged for manual review.', suggested_expected_value: null };
}
const testContext = $('Needs AI Review?').item.json;
return { json: { ...testContext, ai_verdict: verdict } };

const item = $json;
let final;
if (item.ai_verdict) {
  const v = item.ai_verdict;
  final = {
    test_id: item.test_id,
    test_name: item.test_name || null,
    verdict: v.verdict,
    source: 'ai',
    confidence: v.confidence,
    root_cause_category: v.root_cause_category,
    reasoning: v.reasoning,
    suggested_expected_value: v.suggested_expected_value != null ? v.suggested_expected_value : null,
    mismatches: item.mismatches || [],
    priority: item.priority,
    known_flaky: item.known_flaky,
    endpoint: item.endpoint || null,
    run_id: item.run_id
  };
} else if (item.deterministic_verdict === 'UNSUPPORTED') {
  final = {
    test_id: item.test_id,
    test_name: item.test_name || null,
    verdict: 'NEEDS_REVIEW',
    source: 'deterministic',
    confidence: 0,
    root_cause_category: 'TEST_DATA_ISSUE',
    reasoning: 'Unsupported test_type; no execution branch handled this test.',
    suggested_expected_value: null,
    mismatches: item.mismatches || [],
    priority: item.priority,
    known_flaky: item.known_flaky,
    endpoint: item.endpoint || null,
    run_id: item.run_id
  };
} else {
  final = {
    test_id: item.test_id,
    test_name: item.test_name || null,
    verdict: 'PASS',
    source: 'deterministic',
    confidence: 1,
    root_cause_category: null,
    reasoning: 'All deterministic assertions passed; no AI call was needed.',
    suggested_expected_value: null,
    mismatches: [],
    priority: item.priority,
    known_flaky: item.known_flaky,
    endpoint: item.endpoint || null,
    run_id: item.run_id
  };
}
// Accumulate into per-run static data so the 'done' branch can aggregate
// (SplitInBatches 'done' output only emits the ORIGINAL input, not these merged records).
const staticData = $getWorkflowStaticData('global');
const key = 'results_' + final.run_id;
if (!Array.isArray(staticData[key])) staticData[key] = [];
staticData[key].push(final);
return { json: final };

const run = $('Initialize Run').first().json;
const runId = run.run_id;
const staticData = $getWorkflowStaticData('global');
const results = Array.isArray(staticData['results_' + runId]) ? staticData['results_' + runId] : [];
const skipped = Array.isArray(staticData['skipped_' + runId]) ? staticData['skipped_' + runId] : [];

const counts = { pass: 0, fail: 0, flaky: 0, needs_review: 0 };
for (const r of results) {
  if (r.verdict === 'PASS') counts.pass++;
  else if (r.verdict === 'FLAKY') counts.flaky++;
  else if (r.verdict === 'NEEDS_REVIEW') counts.needs_review++;
  else counts.fail++;
}

const failures = results.filter(r => r.verdict === 'FAIL');

// Cluster by (endpoint, root_cause_category) for de-duplicated ticket filing.
const clusters = {};
for (const f of failures) {
  const key = `${f.endpoint || 'n/a'} :: ${f.root_cause_category || 'UNKNOWN'}`;
  if (!clusters[key]) clusters[key] = { endpoint: f.endpoint || null, root_cause_category: f.root_cause_category || 'UNKNOWN', failures: [] };
  clusters[key].failures.push(f);
}

const criticalFail = results.some(r => r.priority === 'critical' && (r.verdict === 'FAIL' || r.verdict === 'NEEDS_REVIEW'));

// Stale-expectation suggestions for human review (written to suggested_updates in Store Run History).
const stale = results.filter(r => r.root_cause_category === 'STALE_EXPECTATION' && r.suggested_expected_value != null)
  .map(r => ({ test_id: r.test_id, suggested_expected_value: r.suggested_expected_value, reasoning: r.reasoning }));

// Clean up this run's accumulator so static data doesn't grow unbounded.
delete staticData['results_' + runId];
delete staticData['skipped_' + runId];

return [{ json: {
  run_id: runId,
  source: run.source,
  build_id: run.build_id || null,
  started_at: run.started_at,
  counts,
  total: results.length,
  results,
  failures,
  clusters,
  skipped,
  stale_suggestions: stale,
  critical_fail: criticalFail
} }];

