let summary;
try {
  const resp = $input.first().json;
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '{}';
  summary = JSON.parse(text.replace(/```json/g, '').replace(/```/g, '').trim());
  if (!summary || typeof summary.risk_rating !== 'string') throw new Error('missing risk_rating');
} catch (e) {
  summary = { risk_rating: 'MEDIUM', headline: 'Summary unavailable - AI parsing failed', top_risks: [], narrative: 'The executive summary could not be generated automatically; please review results manually.' };
}
const agg = $('Aggregate Run Results').first().json;
return [{ json: { ...agg, ...summary } }];

const data = $json;
const items = [];
for (const [key, cluster] of Object.entries(data.clusters || {})) {
  items.push({ json: {
    run_id: data.run_id,
    cluster_key: key,
    endpoint: cluster.endpoint,
    root_cause_category: cluster.root_cause_category,
    failures: cluster.failures,
    count: cluster.failures.length
  } });
}
return items;

